INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('10','wcpay-promo-2020-12','marketing','en_US','wcpay-promo-2020-12','wcpay-promo-2020-12','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('11','ppxo-pps-upgrade-paypal-payments-1','info','en_US','Get the latest PayPal extension for WooCommerce','Heads up! Thereâs a new PayPal on the block!<br /><br />Now is a great time to upgrade to our latest <a href=\"https://woocommerce.com/products/woocommerce-paypal-payments/\" target=\"_blank\">PayPal extension</a> to continue to receive support and updates with PayPal.<br /><br />Get access to a full suite of PayPal payment methods, extensive currency and country coverage, and pay later options with the all-new PayPal extension for WooCommerce.','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('12','ppxo-pps-upgrade-paypal-payments-2','info','en_US','Upgrade your PayPal experience!','Get access to a full suite of PayPal payment methods, extensive currency and country coverage, offer subscription and recurring payments, and the new PayPal pay later options.<br /><br />Start using our <a href=\"https://woocommerce.com/products/woocommerce-paypal-payments/\" target=\"_blank\">latest PayPal today</a> to continue to receive support and updates.','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('13','woocommerce-core-sqli-july-2021-need-to-update','update','en_US','Action required: Critical vulnerabilities in WooCommerce','In response to a critical vulnerability identified on July 13, 2021, we are working with the WordPress Plugins Team to deploy software updates to stores running WooCommerce (versions 3.3 to 5.5) and the WooCommerce Blocks feature plugin (versions 2.5 to 5.5).<br /><br />Our investigation into this vulnerability is ongoing, but <strong>we wanted to let you know now about the importance of updating immediately</strong>.<br /><br />For more information on which actions you should take, as well as answers to FAQs, please urgently review our blog post detailing this issue.','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('14','woocommerce-blocks-sqli-july-2021-need-to-update','update','en_US','Action required: Critical vulnerabilities in WooCommerce Blocks','In response to a critical vulnerability identified on July 13, 2021, we are working with the WordPress Plugins Team to deploy software updates to stores running WooCommerce (versions 3.3 to 5.5) and the WooCommerce Blocks feature plugin (versions 2.5 to 5.5).<br /><br />Our investigation into this vulnerability is ongoing, but <strong>we wanted to let you know now about the importance of updating immediately</strong>.<br /><br />For more information on which actions you should take, as well as answers to FAQs, please urgently review our blog post detailing this issue.','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('15','woocommerce-core-sqli-july-2021-store-patched','update','en_US','Solved: Critical vulnerabilities patched in WooCommerce','In response to a critical vulnerability identified on July 13, 2021, we worked with the WordPress Plugins Team to deploy software updates to stores running WooCommerce (versions 3.3 to 5.5) and the WooCommerce Blocks feature plugin (versions 2.5 to 5.5).<br /><br /><strong>Your store has been updated to the latest secure version(s)</strong>. For more information and answers to FAQs, please review our blog post detailing this issue.','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('16','woocommerce-blocks-sqli-july-2021-store-patched','update','en_US','Solved: Critical vulnerabilities patched in WooCommerce Blocks','In response to a critical vulnerability identified on July 13, 2021, we worked with the WordPress Plugins Team to deploy software updates to stores running WooCommerce (versions 3.3 to 5.5) and the WooCommerce Blocks feature plugin (versions 2.5 to 5.5).<br /><br /><strong>Your store has been updated to the latest secure version(s)</strong>. For more information and answers to FAQs, please review our blog post detailing this issue.','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('17','habit-moment-survey','marketing','en_US','Weâre all ears! Share your experience so far with WooCommerce','Weâd love your input to shape the future of WooCommerce together. Feel free to share any feedback, ideas or suggestions that you have.','{}','unactioned','woocommerce.com','2025-11-23 18:57:36',NULL,'0','plain','','0','1','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('18','woocommerce-core-paypal-march-2022-updated','update','en_US','Security auto-update of WooCommerce','<strong>Your store has been updated to the latest secure version of WooCommerce</strong>. We worked with WordPress to deploy PayPal Standard security updates for stores running WooCommerce (version 3.5 to 6.3). Itâs recommended to disable PayPal Standard, and use <a href=\"https://woocommerce.com/products/woocommerce-paypal-payments/\" target=\"_blank\">PayPal Payments</a> to accept PayPal.','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('19','woocommerce-core-paypal-march-2022-updated-nopp','update','en_US','Security auto-update of WooCommerce','<strong>Your store has been updated to the latest secure version of WooCommerce</strong>. We worked with WordPress to deploy security updates related to PayPal Standard payment gateway for stores running WooCommerce (version 3.5 to 6.3).','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('20','pinterest_03_2022_update','marketing','en_US','Your Pinterest for WooCommerce plugin is out of date!','Update to the latest version of Pinterest for WooCommerce to continue using this plugin and keep your store connected with Pinterest. To update, visit <strong>Plugins &gt; Installed Plugins</strong>, and click on âupdate nowâ under Pinterest for WooCommerce.','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('21','store_setup_survey_survey_q2_2022','survey','en_US','How is your store setup going?','Our goal is to make sure you have all the right tools to start setting up your store in the smoothest way possible.\r\nWeâd love to know if we hit our mark and how we can improve. To collect your thoughts, we made a 2-minute survey.','{}','unactioned','woocommerce.com','2025-10-21 06:10:56',NULL,'0','plain','','0','1','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('22','needs-update-eway-payment-gateway-rin-2022-12-20','update','en_US','Security vulnerability patched in WooCommerce Eway Gateway','In response to a potential vulnerability identified in WooCommerce Eway Gateway versions 3.1.0 to 3.5.0, weâve worked to deploy security fixes and have released an updated version.\r\nNo external exploits have been detected, but we recommend you update to your latest supported version 3.1.26, 3.2.3, 3.3.1, 3.4.6, or 3.5.1','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('23','updated-eway-payment-gateway-rin-2022-12-20','update','en_US','WooCommerce Eway Gateway has been automatically updated','Your store is now running the latest secure version of WooCommerce Eway Gateway. We worked with the WordPress Plugins team to deploy a software update to stores running WooCommerce Eway Gateway (versions 3.1.0 to 3.5.0) in response to a security vulnerability that was discovered.','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
