INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('50','sirt-woo-2024-11-xss-admin','update','en_US','An important update is required for WooCommerce','This update addresses a security vulnerability that could allow unauthorized access to administrative privileges on your site. <a href=\"https://developer.woocommerce.com/2024/12/03/woocommerce-9-4-3-and-woocommerce-9-3-4-available-now/\">Learn more</a>.\r\n<br><br>\r\n<strong>Please ensure your site is updated to the latest version to stay secure.</strong>','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('51','paypal-braintree-sdk-depreciation-2025-02-20','update','en_US','Update required for your PayPal Braintree extension','To continue securely accepting payments, you must update your PayPal Braintree extension to version 3.2.4 or newer before June 30, 2025. Your current extension version will not support payment processing after this date due to an SSL certificate update.','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('52','uk-vat-notice-2025-04-30','warning','en_US','UK VAT numbers are no longer supported','Due to recent HM Revenue &amp; Customs (HMRC) VAT API changes, your EU VAT Number for WooCommerce extension can no longer validate UK VAT numbers. HMRC now requires merchants to register an API key, which this extension does not currently support. We recommend EU/UK VAT Validation Manager for WooCommerce as a replacement','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('53','payson-retirement-2025','update','en_US','Payson Form Retirement','Svea Bank is discontinuing the Payson service; the last date for transactions is August 31, 2025. As a result, the Payson Form extension has been removed from WooCommerce.com. Documentation remains available.','{}','pending','woocommerce.com','2025-10-13 16:59:22',NULL,'0','plain','','0','0','info');
