INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('73','snap_q4_2025','marketing','en_US','New: Reach a new audience on Snapchat','88% of Snapchatters love to shop, and 40% aren\'t active on other social platforms. Connect with them and grow your business using Snapchat for WooCommerce, our new official extension. Sync your products, launch ad campaigns, and track results â all from your Woo dashboard.','{}','pending','woocommerce.com','2025-12-19 09:09:43',NULL,'0','plain','','0','0','info');
