INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('76','WC10.4.3-security-update-12-22-2025','update','en_US','An important update is required for WooCommerce','<strong>Please update to WooCommerce 10.4.3 to resolve a security issue.</strong> This update addresses an issue with the WooCommerce Store API that may have made guest order information visible to other logged in users. See the <a href=\"https://developer.woocommerce.com/2025/12/22/store-api-vulnerability-patched-in-woocommerce-8-1/\" target=\"_blank\">Woo Developer blog</a> for more information.','{}','pending','woocommerce.com','2025-12-23 10:08:06',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('77','downloads-sub-Jan2026-RIN','marketing','en_US','WooCommerce Subscription Downloads is now part of WooCommerce Subscriptions','WooCommerce Subscriptions now allows you to include simple and variable downloadable products with your subscriptions. Streamline your subscription downloads by updating to the latest version of WooCommerce Subscriptions today.','{}','unactioned','woocommerce.com','2026-01-07 20:37:37',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('78','wc-admin-real-time-order-alerts','info','en_US','Get real-time order alerts anywhere','Get notifications about store activity, including new orders and product reviews directly on your mobile devices with the Woo app.','{}','unactioned','woocommerce-admin','2026-01-11 19:47:44',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('79','paypal-carding-recaptcha-jan-26','update','en_US','Fraud protection is now required â enable today','Card networks like Visa and Mastercard now require fraud prevention controls, and non-compliance may result in fines and processing restrictions. Please enable reCAPTCHA in your PayPal Payments settings to help protect your store and maintain compliance.','{}','pending','woocommerce.com','2026-01-13 04:31:07',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('80','USPS API Migration_RIN_Jan2026','marketing','en_US','Upgrade to USPS Shipping REST API by January 25','USPS is retiring the legacy Web Tools API on January 25, 2026. If youâre using the USPS Shipping Method extension with the legacy API, live USPS shipping rates will longer be shown at checkout. Migrate to the REST API now to avoid disruption.','{}','pending','woocommerce.com','2026-01-14 18:26:49',NULL,'0','plain','','0','0','info');
