INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('83','wc-admin-scheduled-updates-promotion','info','en_US','Analytics now supports scheduled updates','This provides improved performance to your store, enable it in Analytics &gt; Settings.','{}','unactioned','woocommerce-admin','2026-02-04 20:28:22',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('84','reddit_q1_2026','marketing','en_US','Start advertising on Reddit with a $1,000 bonus','Make the most of our new Reddit integration with $1,000 in Reddit Ads! For a limited time, new advertisers who spend $1,000 in Reddit Ads Manager over 30 days will get $1,000 in ad credit. Your bonus credit unlocks automatically when you hit $1,000 in spend. Use your credit within 30 days.','{}','unactioned','woocommerce.com','2026-02-06 06:36:52',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('85','Googleupdate_q1_2026','marketing','en_US','Make every ad dollar count','Google for WooCommerce now includes Budget Recommendations. Promote your products across Google â from Search to YouTube and beyond â and get personalized suggestions on where to optimize campaign budgets to reach more shoppers.','{}','unactioned','woocommerce.com','2026-02-12 18:22:58',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('86','Mailchimp-API-maintenance-feb-2026','update','en_US','Mailchimp Maintenance Feb 28','Mailchimp will be carrying out planned API maintenance on February 28 from 11am â 4pm EST. During that time, you may see brief sync interruptions in Mailchimp for WooCommerce. Most data will catch up automatically. See the <a href=\"https://developer.woocommerce.com/2026/02/27/mailchimp-api-maintenance-february-28/\" target=\"_blank\">Woo Developer blog</a> for more information.','{}','pending','woocommerce.com','2026-02-27 18:17:44',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('87','RIN-WC-Security-Update-admin-update-March-2026','update','en_US','An important update is required for WooCommerce','<strong>Update to WooCommerce 10.5.3 or the latest version to resolve a security issue.</strong> This update addresses a vulnerability in WooCommerce versions 5.4 to 10.5.2 that could have permitted unauthorized admin account access. See the <a href=\"https://developer.woocommerce.com/2026/03/02/store-api-vulnerability-patched-in-woocommerce-5-4/\" target=\"_blank\">Woo Developer blog</a> for more information.','{}','pending','woocommerce.com','2026-03-04 09:04:54',NULL,'0','plain','','0','0','info');
INSERT INTO `wp_wc_admin_notes` (`note_id`,`name`,`type`,`locale`,`title`,`content`,`content_data`,`status`,`source`,`date_created`,`date_reminder`,`is_snoozable`,`layout`,`image`,`is_deleted`,`is_read`,`icon`) VALUES('88','USPS_Scan_Form_Mar2026','marketing','en_US','New: Save time shipping with USPS SCAN Form','USPS SCAN Form consolidates multiple shipments into one scannable sheet. Hand off all your orders at once â no more scanning packages individually. Select âCreate SCAN Formâ under your orders to try it today.','{}','pending','woocommerce.com','2026-03-12 06:46:54',NULL,'0','plain','','0','0','info');
